                                var speedMbps = elapsedSeconds > 0 ? (bytesDownloaded * 8) / (elapsedSeconds * 1_000_000) : 0;

                                progressCallback?.Invoke(_downloadProgress);
                                OnDownloadProgressChanged(_downloadProgress, bytesDownloaded, totalBytes, speedMbps);
                            }
                        }
                    }

